import { Workflow, suspend } from '@mastra/core';
import { z } from 'zod';

export const contentApprovalWorkflow = new Workflow({
  name: 'contentApprovalWorkflow',
  inputSchema: {
    content: z.string(),
  },
  outputSchema: {
    result: z.string(),
  },
});

const reviewStep = contentApprovalWorkflow.step({
  id: 'reviewStep',
  resumeSchema: {
    approved: z.boolean(),
  },
  execute: async ({ context, resumeData }) => {
    const { content } = context;

    // Suspend if resumeData is not provided
    if (!resumeData) {
      await suspend();
      // This line won't be reached until the workflow is resumed
    }

    // After resumption, process based on approval status
    const result = resumeData!.approved
      ? `Publish: ${content}`
      : `Discard: ${content}`;

    return { result };
  },
});

// Set the workflow output to match the step's output
contentApprovalWorkflow.setOutput(reviewStep);

