import { Mastra } from '@mastra/core';
import { contentApprovalWorkflow } from './workflow';
import { writeFileSync } from 'fs';

// Initialize a Mastra instance with the workflow
const mastra = new Mastra({
  workflows: [contentApprovalWorkflow],
});

async function main() {
  // Start a run with input
  const run = await mastra.startRun({
    workflowId: 'contentApprovalWorkflow',
    input: { content: 'Hello World' },
  });

  // Check if the run status is "suspended"
  if (run.status === 'suspended') {
    console.log('Workflow is suspended, resuming...');

    // Resume the run with resumeData
    const resumedRun = await mastra.resumeRun({
      runId: run.id,
      resumeData: { approved: true },
    });

    // Write the final workflow result to output.json
    writeFileSync(
      '/home/user/mastra-app/output.json',
      JSON.stringify(resumedRun.result, null, 2)
    );

    console.log('Result written to output.json:', resumedRun.result);
  } else {
    console.log('Run status:', run.status);
  }
}

main().catch(console.error);

