import { createWorkflow, createStep, suspend } from '@mastra/core/workflows';
import { z } from 'zod';

const reviewStep = createStep({
  id: 'reviewStep',
  resumeSchema: z.object({
    approved: z.boolean(),
  }),
  execute: async ({ inputData, resumeData }) => {
    const { content } = inputData;

    // Suspend if resumeData is not provided
    if (!resumeData) {
      await suspend();
      // This line won't be reached until the workflow is resumed
    }

    // After resumption, process based on approval status
    const result = resumeData!.approved
      ? `Publish: ${content}`
      : `Discard: ${content}`;

    return { result };
  },
});

export const contentApprovalWorkflow = createWorkflow({
  id: 'contentApprovalWorkflow',
  inputSchema: z.object({
    content: z.string(),
  }),
  outputSchema: z.object({
    result: z.string(),
  }),
}).then(reviewStep).commit();

